local TD = TD.td1madao["ydj_dst_td1madao"] local function enablePlayer(inst)     if inst.components.playercontroller ~= nil then         inst.components.playercontroller:Enable(true)     end     TD.server(function()         TD.addC(inst, "health"):SetInvincible(false)     end)     TD.show(inst) end local function timeOut(inst)     enablePlayer(inst)     TD.goto(inst, "idle") end local gunAttack = _G.State {     name = TD.holder("%s_player_gun_attack"),     tags = { "attack", "notalking", "abouttoattack", },     onenter = function(inst)         if TD.ds() then             TD.showShip(5)         end         inst.components.locomotor:Stop()         TD.server(function()             local buffaction = inst:GetBufferedAction()             local target = buffaction ~= nil and buffaction.target or nil             TD.hasC(inst, "combat", function(comp)                 comp:SetTarget(target)                 comp:StartAttack()                 inst.sg:SetTimeout(18)             end)             if target ~= nil and target:IsValid() then                 inst:FacePoint(target.Transform:GetWorldPosition())                 inst.sg.statemem.attacktarget = target             end         end, function()             local buffaction = inst:GetBufferedAction()             if buffaction ~= nil then                 inst:PerformPreviewBufferedAction()                 if buffaction.target ~= nil and buffaction.target:IsValid() then                     inst:FacePoint(buffaction.target:GetPosition())                     inst.sg.statemem.attacktarget = buffaction.target                 end             end             if inst.replica.combat ~= nil then                 inst.replica.combat:StartAttack()             end         end)         inst.AnimState:PlayAnimation(TD.holder("%s_attack"))     end,     timeline =     {         _G.TimeEvent(3 * _G.FRAMES, function(inst)             inst.SoundEmitter:PlaySound("dontstarve/wilson/attack_firestaff")         end),         _G.TimeEvent(7 * _G.FRAMES, function(inst)             inst.sg:RemoveStateTag("abouttoattack")             TD.server(function()                 local sq = TD.below(inst, TD.holder("%s_air_sword"))                 sq.Transform:SetRotation(inst.Transform:GetRotation())                 TD.hasC(inst, "combat", function(comp)                     if TD.dst() then                         inst:PerformBufferedAction()                     else                         comp:DoAttack(inst.sg.statemem.target)                     end                 end)             end)         end),         _G.TimeEvent(12 * _G.FRAMES, function(inst)             inst.sg:RemoveStateTag("attack")         end),     },     events =     {         _G.EventHandler("animover", function(inst)             TD.goto(inst, "idle")         end),     },     ontimeout = function(inst)         inst.sg:RemoveStateTag("attack")         TD.goto(inst, "idle")         if TD.ds() then             TD.hideShip()         end     end,     onexit = function(inst)         if inst.sg:HasStateTag("abouttoattack") then             TD.server(function()                 inst.components.combat:SetTarget(nil)                 if TD.dst() then                     TD.hasC(inst, "combat", function(comp)                         comp:CancelAttack()                     end)                 else                     TD.hasC(inst, "combat", function(comp)                         comp.laststartattacktime = 0                     end)                 end             end, function()                 if inst.sg:HasStateTag("abouttoattack") and inst.replica.combat ~= nil then                     if TD.dst() then                         if inst and inst.replica and inst.replica.combat and inst.replica.combat.CancelAttack then                             inst.replica.combat:CancelAttack()                         end                     else                         TD.hasC(inst, "combat", function(comp)                             comp.laststartattacktime = 0                         end)                     end                 end             end)         end         if TD.ds() then             TD.hideShip()         end     end, } AddStategraphState("wilson", gunAttack) if TD.ds() then     AddStategraphState("wilsonboating", gunAttack) else     AddStategraphState("wilson_client", gunAttack) end 